import { useState, useEffect } from "react";

function ViewApplications() {
  const [apps, setApps] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("applications")) || [];
    setApps(stored);
  }, []);

  const updateStatus = (id, status) => {
    const updated = apps.map((app) =>
      app.id === id ? { ...app, status } : app
    );

    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));

    alert(`Application ${status}`);
  };

  // 🔥 FINAL NAME RESOLVER (Guaranteed)
  const getEmployeeName = (app) => {
    const email = (app.email || "").toLowerCase().trim();
    const empId = (app.empId || "").toString().trim();

    console.log("Resolving Name For:", app);

    // 1️⃣ direct stored name
    if (app.employee) return app.employee;
    if (app.employeeName) return app.employeeName;

    // 2️⃣ employees table
    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const emp = employees.find(
      (e) =>
        (e.empId && e.empId.toString().trim() === empId) ||
        (e.id && e.id.toString().trim() === empId) ||
        (e.email && e.email.toLowerCase().trim() === email)
    );
    if (emp?.name) return emp.name;

    // 3️⃣ users table
    const users = JSON.parse(localStorage.getItem("users")) || [];
    const user = users.find(
      (u) =>
        (u.empId && u.empId.toString().trim() === empId) ||
        (u.username && u.username.toLowerCase().trim() === email) ||
        (u.email && u.email.toLowerCase().trim() === email)
    );
    if (user?.name) return user.name;

    return "Unknown";
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications (Admin)</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {apps.length === 0 ? (
            <tr>
              <td colSpan="7" style={{ textAlign: "center" }}>
                No Applications Found
              </td>
            </tr>
          ) : (
            apps.map((a, index) => (
              <tr key={a.id}>
                <td>{index + 1}</td>

                <td>{getEmployeeName(a)}</td>

                <td>{a.email || "N/A"}</td>

                <td>{a.jobTitle}</td>

                <td>
                  <span
                    style={{
                      padding: "6px 12px",
                      borderRadius: "6px",
                      fontWeight: "600",
                      color: "white",
                      background:
                        a.status === "Approved"
                          ? "green"
                          : a.status === "Rejected"
                          ? "red"
                          : "#64748b",
                    }}
                  >
                    {a.status}
                  </span>
                </td>

                <td>{a.appliedDate || "--"}</td>

                <td style={{ display: "flex", gap: "12px" }}>
                  <button
                    style={{
                      background: "#16a34a",
                      color: "white",
                      padding: "6px 14px",
                      borderRadius: "6px",
                      border: "none",
                      cursor: "pointer",
                    }}
                    onClick={() => updateStatus(a.id, "Approved")}
                  >
                    Approve
                  </button>

                  <button
                    style={{
                      background: "#dc2626",
                      color: "white",
                      padding: "6px 14px",
                      borderRadius: "6px",
                      border: "none",
                      cursor: "pointer",
                    }}
                    onClick={() => updateStatus(a.id, "Rejected")}
                  >
                    Reject
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
